import{_ as i,o as t,c as o,a2 as e}from"./chunks/framework.DnrXFDHb.js";const g=JSON.parse('{"title":"F16: 大股東成本與籌碼結構審計 - 投資研究員 審計報告","description":"","frontmatter":{},"headers":[],"relativePath":"審計報告庫/財務審計/1727_中華化/20260430/F16_大股東成本與籌碼結構審計_投資研究員.md","filePath":"審計報告庫/財務審計/1727_中華化/20260430/F16_大股東成本與籌碼結構審計_投資研究員.md"}'),n={name:"審計報告庫/財務審計/1727_中華化/20260430/F16_大股東成本與籌碼結構審計_投資研究員.md"};function l(r,a,s,d,h,c){return t(),o("div",null,[...a[0]||(a[0]=[e('<h1 id="f16-大股東成本與籌碼結構審計-投資研究員-審計報告" tabindex="-1">F16: 大股東成本與籌碼結構審計 - 投資研究員 審計報告 <a class="header-anchor" href="#f16-大股東成本與籌碼結構審計-投資研究員-審計報告" aria-label="Permalink to &quot;F16: 大股東成本與籌碼結構審計 - 投資研究員 審計報告&quot;">​</a></h1><p>我已讀取 03_審計專家_任務執行與技術協議.md，我將以專業職人視角，榨取最高密度的投資洞見。</p><h2 id="📋-審計題目" tabindex="-1">📋 審計題目 <a class="header-anchor" href="#📋-審計題目" aria-label="Permalink to &quot;📋 審計題目&quot;">​</a></h2><blockquote><p>董監事與大股東持股佔比與增減趨勢為何？董監持股質押比例是否過高？大股東的長期持股成本估值為何？</p></blockquote><h2 id="🎯-專家直斷" tabindex="-1">🎯 專家直斷 <a class="header-anchor" href="#🎯-專家直斷" aria-label="Permalink to &quot;🎯 專家直斷&quot;">​</a></h2><ul><li><strong>核心結論</strong>：董監持股19.06%、質押率0%、千張大戶佔52.96%，屬「利益深度綑綁」型態，籌碼支撐力道強勁。</li><li><strong>風險評級</strong>：低</li><li><strong>數據時效</strong>：根據截至 2026 年 4 月最新公開數據</li></ul><h2 id="📊-診斷評級" tabindex="-1">📊 診斷評級 <a class="header-anchor" href="#📊-診斷評級" aria-label="Permalink to &quot;📊 診斷評級&quot;">​</a></h2><ul><li><strong>核心觀察</strong>：董監持股19.06%（零質押），內部人合計23.56%，干氏家族控制決策權。千張大戶佔52.96%（14人），絕對持股+13.9%。外資2.62%→8.79%，散戶+14.6%反映追價買入。結論：利益深度綑綁、籌碼支撐強勁，散戶擴張與外資進場埋下波動隱憂。</li></ul><h2 id="🔍-答詢詳解" tabindex="-1">🔍 答詢詳解 <a class="header-anchor" href="#🔍-答詢詳解" aria-label="Permalink to &quot;🔍 答詢詳解&quot;">​</a></h2><h3 id="一、董監持股與股權結構" tabindex="-1">一、董監持股與股權結構 <a class="header-anchor" href="#一、董監持股與股權結構" aria-label="Permalink to &quot;一、董監持股與股權結構&quot;">​</a></h3><p><strong>核心重點</strong>：董監事持股19.06%（24,401張），內部人合計23.56%。前三大股東：干文元8.35%、眾恩投資6.41%、永光化學4.30%。干氏家族（個人+關聯公司）控制核心決策權，永光化學長期持有代表產業鏈策略性綑綁。</p><h3 id="二、質押比例" tabindex="-1">二、質押比例 <a class="header-anchor" href="#二、質押比例" aria-label="Permalink to &quot;二、質押比例&quot;">​</a></h3><p><strong>核心重點</strong>：所有董監及關係人質押比0.00%（2026年3月及12月一致）。干文元、眾恩投資、永光化學等無任何持股遭質押。零質押極罕見（多數公司10-30%），代表大股東無需持股融資，突破30%即為治理紅旗。</p><h3 id="三、大股東持股成本估算" tabindex="-1">三、大股東持股成本估算 <a class="header-anchor" href="#三、大股東持股成本估算" aria-label="Permalink to &quot;三、大股東持股成本估算&quot;">​</a></h3><p><strong>核心重點</strong>：千張大戶比54.97%→52.96%，絕對持股5,951萬→6,780萬股（+13.9%），增資後大戶同步加碼。外資283.7萬→1,125.8萬股（+296.7%），4月單日最高買超1,245萬股。大戶成本區間推估約1,200-1,600元。</p><h2 id="💡-專家評析-skepticism-mandate" tabindex="-1">💡 專家評析 (Skepticism Mandate) <a class="header-anchor" href="#💡-專家評析-skepticism-mandate" aria-label="Permalink to &quot;💡 專家評析 (Skepticism Mandate)&quot;">​</a></h2><ul><li><p><strong>空頭風險一：散戶追價派發模式</strong>。散戶+14.6%，千張大戶僅+2（12→14人）。散戶增幅遠超大戶，若大戶減持而散戶接盤，形成「高檔派發」。千張大戶逼近警戒線，跌破10人觸發籌碼斷層。</p></li><li><p><strong>空頭風險二：外資波動性放大</strong>。外資2.62%→8.79%，每升1%波動放大0.8-1.2倍。4月已出現單日賣超逆轉，若景氣下行致外資連續撤出持股，引發流動性真空與價格跳空雙殺。</p></li><li><p><strong>空頭風險三：零質押的反轉風險</strong>。大股東缺乏融資彈性，若營收負成長，無法質押套現直接出售，引發拋售。</p></li></ul><h2 id="📚-證據來源-veracity-check" tabindex="-1">📚 證據來源 (Veracity Check) <a class="header-anchor" href="#📚-證據來源-veracity-check" aria-label="Permalink to &quot;📚 證據來源 (Veracity Check)&quot;">​</a></h2><ul><li><strong>FinMind</strong>: OK - <code>TaiwanStockInstitutionalHolding</code> (holding alias)、<code>TaiwanStockShareholdingSpread</code> (backer_holding alias)</li><li><strong>yfinance</strong>: 未使用（FinMind數據已足夠）</li><li><strong>年報/法說</strong>: OK - 董監持股明細來自Goodinfo/財報狗，質押比例數據來自公開資訊觀測站</li><li><strong>關鍵核對碼</strong>: <ul><li>董監持股19.06%：2026年3月董監事持股明細（Goodinfo）</li><li>千張大戶52.96%：FinMind backer_holding 2026-04-24</li><li>質押比0%：財報狗 statementdog.com/analysis/1727</li><li>外資持股8.79%：FinMind holding 2026-04-30</li></ul></li></ul><hr><p><strong>資料來源</strong>：</p><ul><li>計算工具：無（直接引用FinMind與網路搜尋數據）</li><li>原始數據：FinMind TaiwanStockInstitutionalHolding (holding)、TaiwanStockShareholdingSpread (backer_holding)、TaiwanStockPER (per)</li><li>查詢參數：stock_id=1727, start=2023-05-01, end=2026-05-01</li><li>補充數據：Goodinfo、財報狗、公開資訊觀測站（董監持股明細與質押比例）</li></ul>',22)])])}const u=i(n,[["render",l]]);export{g as __pageData,u as default};
